const raw = $('Launch Agent Like Scrape Async').first().json.data;

const events = raw
  .split('\n')
  .filter(Boolean)
  .map(line => { try { return JSON.parse(line); } catch { return null; } })
  .filter(Boolean);

const summary = events.find(e => e.type === 'summary')?.data || {};

let resultJsonUrl = null;
for (const e of events) {
  if (e.type !== 'logs') continue;
  for (const line of e.data) {
    const match = line.match(/https:\/\/[^\s]+result\.json/);
    if (match) { resultJsonUrl = match[0]; break; }
  }
  if (resultJsonUrl) break;
}

return {
  json: {
    containerId: summary.containerId ?? null,
    executionTime: summary.executionTime ?? null,
    exitCode: summary.exitCode ?? null,
    resultJsonUrl
  }
};

const raw = $('Launch Agent Scrape Post').first().json.data;

const events = raw
  .split('\n')
  .filter(Boolean)
  .map(line => { try { return JSON.parse(line); } catch { return null; } })
  .filter(Boolean);

const summary = events.find(e => e.type === 'summary')?.data || {};

let resultJsonUrl = null;
const errorMessages = [];

for (const e of events) {
  if (e.type !== 'logs') continue;
  for (const line of e.data) {
    if (!resultJsonUrl) {
      const match = line.match(/https:\/\/[^\s]+result\.json/);
      if (match) resultJsonUrl = match[0];
    }
    const errorMatch = line.match(/^\[error\].*?Error:(.*)/);
    if (errorMatch) errorMessages.push(errorMatch[1].trim());
  }
}

return {
  json: {
    containerId: summary.containerId ?? null,
    executionTime: summary.executionTime ?? null,
    exitCode: summary.exitCode ?? null,
    resultJsonUrl,
    errorMessage: errorMessages.length ? errorMessages.join(' | ') : null
  }
};

